  1	import * as React from 'react';
  2	import { render, screen } from '@testing-library/react';
  3	import { MemoryRouter } from 'react-router-dom';
  4	import { SVGDefsProvider } from '@patternfly/react-topology';
  5	import { useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
  6	import { ConnectedPipelineRunDecorator } from '../PipelineRunDecorator';
  7	import { connectedPipelineOne } from './decorator-data';
  8	import Status from '../../../status/Status';
  9	import {
 10	  getTaskRunsOfPipelineRun,
 11	  useTaskRunsK8s,
 12	} from '../../../hooks/useTaskRuns';
 13	
 14	jest.mock('@openshift-console/dynamic-plugin-sdk', () => ({
 15	  ...jest.requireActual('@openshift-console/dynamic-plugin-sdk'),
 16	  useAccessReview: jest.fn(),
 17	  useModal: () => jest.fn(),
 18	  AccessReviewResourceAttributes: {},
 19	}));
 20	
 21	jest.mock('../../../start-pipeline/StartPipelineModal', () => () => (
 22	  <div data-testid="mock-start-pipeline-modal">Mocked StartPipelineModal</div>
 23	));
 24	
 25	jest.mock('react-dnd', () => ({
 26	  DndProvider: ({ children }: { children: React.ReactNode }) => children,
 27	}));
 28	jest.mock('react-dnd-html5-backend', () => ({
 29	  NativeTypes: {
 30	    FILE: 'file',
 31	  },
 32	}));
 33	
 34	jest.mock('../../../hooks/useTaskRuns', () => ({
 35	  useTaskRunsK8s: jest.fn(),
 36	  getTaskRunsOfPipelineRun: jest.fn(() => []),
 37	}));
 38	
 39	jest.mock('../../../utils/common-utils', () => ({
 40	  t: (key: string, params?: Record<string, any>) => {
 41	    if (params) {
 42	      return Object.entries(params).reduce(
 43	        (str, [k, v]) => str.replace(`{{${k}}}`, v),
 44	        key,
 45	      );
 46	    }
 47	    return key;
 48	  },
 49	}));
 50	
 51	jest.mock('../../../status/Status', () => {
 52	  const mockStatus = jest.fn(() => <div>StatusMock</div>);
 53	  return {
 54	    __esModule: true,
 55	    default: mockStatus,
 56	  };
 57	});
 58	
 59	jest.mock('react-i18next', () => ({
 60	  useTranslation: () => ({
 61	    t: (key: string) => key,
 62	    i18n: { changeLanguage: jest.fn() },
 63	  }),
 64	  withTranslation: () => (Component: any) => {
 65	    Component.defaultProps = {
 66	      ...(Component.defaultProps || {}),
 67	      t: (key: string) => key,
 68	    };
 69	    return Component;
 70	  },
 71	}));
 72	
 73	describe('ConnectedPipelineRunDecorator (RTL)', () => {
 74	  const mockUseAccessReview = useAccessReview as jest.Mock;
 75	  const mockUseTaskRunsK8s = useTaskRunsK8s as jest.Mock;
 76	  const mockGetTaskRunsOfPipelineRun = getTaskRunsOfPipelineRun as jest.Mock;
 77	  const mockStatus = Status as jest.Mock;
 78	
 79	  beforeEach(() => {
 80	    jest.clearAllMocks();
 81	    mockUseAccessReview.mockReturnValue(true);
 82	    mockUseTaskRunsK8s.mockReturnValue([[], true]);
 83	    mockGetTaskRunsOfPipelineRun.mockReturnValue([]);
 84	  });
 85	
 86	  it('renders a Link when a PipelineRun is available', () => {
 87	    render(
 88	      <MemoryRouter>
 89	        <SVGDefsProvider>
 90	          <ConnectedPipelineRunDecorator
 91	            pipeline={connectedPipelineOne.pipeline}
 92	            pipelineRuns={connectedPipelineOne.pipelineRuns}
 93	            radius={10}
 94	            x={5}
 95	            y={5}
 96	          />
 97	        </SVGDefsProvider>
 98	      </MemoryRouter>,
 99	    );
100	
101	    const link = screen.getByRole('link');
102	    expect(link).toBeDefined();
103	    expect(link.getAttribute('href')).not.toBeNull();
104	    expect(link.getAttribute('href')).toMatch(/\/logs$/);
105	  });
106	
107	  it('renders a clickable bubble when no PipelineRuns but has permission', () => {
108	    mockStatus.mockImplementationOnce(() => (
109	      <div aria-label="Pipeline not started">Pipeline not started</div>
110	    ));
111	
112	    render(
113	      <MemoryRouter>
114	        <SVGDefsProvider>
115	          <ConnectedPipelineRunDecorator
116	            pipeline={connectedPipelineOne.pipeline}
117	            pipelineRuns={[]}
118	            radius={10}
119	            x={5}
120	            y={5}
121	          />
122	        </SVGDefsProvider>
123	      </MemoryRouter>,
124	    );
125	
126	    const bubble = screen.getByLabelText(/Pipeline not started/i);
127	    expect(bubble).toBeDefined();
128	  });
129	
130	  it('renders a non-clickable bubble when no PipelineRuns and no permission', () => {
131	    mockUseAccessReview.mockReturnValue(false);
132	    mockStatus.mockImplementationOnce(() => (
133	      <div aria-label="Pipeline not started">Pipeline not started</div>
134	    ));
135	
136	    render(
137	      <MemoryRouter>
138	        <SVGDefsProvider>
139	          <ConnectedPipelineRunDecorator
140	            pipeline={connectedPipelineOne.pipeline}
141	            pipelineRuns={[]}
142	            radius={10}
143	            x={5}
144	            y={5}
145	          />
146	        </SVGDefsProvider>
147	      </MemoryRouter>,
148	    );
149	
150	    const bubble = screen.getByLabelText(/Pipeline not started/i);
151	    expect(bubble).toBeDefined();
152	    expect(screen.queryByRole('link')).toBeNull();
153	  });
154	});

